type Node = {
  value: number;
  height: number;
  left: any;
  right: any;
};

function getHeight(node: Node | null): number {
  return node ? node.height : 0;
}

function getBalance(node: Node | null): number {
  return node ? getHeight(node.left) - getHeight(node.right) : 0;
}

function updateHeight(node: Node): void {
  node.height = 1 + Math.max(getHeight(node.left), getHeight(node.right));
}

function rotateRight(y: Node): Node {
  const x = y.left!;
  const T2 = x.right;

  x.right = y;
  y.left = T2;

  updateHeight(y);
  updateHeight(x);

  return x;
}

function rotateLeft(x: Node): Node {
  const y = x.right!;
  const T2 = y.left;

  y.left = x;
  x.right = T2;

  updateHeight(x);
  updateHeight(y);

  return y;
}

function insert(node: Node | null, value: number): Node | null {
  if (!node) {
    return { value, height: 1, left: null, right: null };
  }

  if (value < node.value) {
    node.left = insert(node.left, value);
  } else if (value > node.value) {
    node.right = insert(node.right, value);
  } else {
    return node;
  }

  updateHeight(node);

  const balance = getBalance(node);

  if (balance > 1 && value < node.left!.value) {
    return rotateRight(node);
  }

  if (balance < -1 && value > node.right!.value) {
    return rotateLeft(node);
  }

  if (balance > 1 && value > node.left!.value) {
    node.left = rotateLeft(node.left!);
    return rotateRight(node);
  }

  if (balance < -1 && value < node.right!.value) {
    node.right = rotateRight(node.right!);
    return rotateLeft(node);
  }

  return node;
}

export function avlTreeInsertRebalance(values: number[]): {value: number; height: number; left: any; right: any} | null {
  let root: Node | null = null;
  for (const val of values) {
    root = insert(root, val);
  }
  return root;
}

