interface TrieNode {
  children: Map<string, TrieNode>;
  isEnd: boolean;
}

export function trieAutocomplete(words: string[], prefixes: string[]): string[][] {
  const root: TrieNode = { children: new Map(), isEnd: false };

  for (const word of words) {
    let node = root;
    for (const char of word) {
      if (!node.children.has(char)) {
        node.children.set(char, { children: new Map(), isEnd: false });
      }
      node = node.children.get(char)!;
    }
    node.isEnd = true;
  }

  const results: string[][] = [];

  for (const prefix of prefixes) {
    let node = root;
    let found = true;
    for (const char of prefix) {
      if (!node.children.has(char)) {
        found = false;
        break;
      }
      node = node.children.get(char)!;
    }

    if (!found) {
      results.push([]);
      continue;
    }

    const completions: string[] = [];
    const stack: [TrieNode, string][] = [[node, prefix]];

    while (stack.length > 0) {
      const [currNode, currentStr] = stack.pop()!;
      if (currNode.isEnd) {
        completions.push(currentStr);
      }
      const keys = [...currNode.children.keys()].sort();
      for (let i = keys.length - 1; i >= 0; i--) {
        stack.push([currNode.children.get(keys[i])!, currentStr + keys[i]]);
      }
    }

    results.push(completions);
  }

  return results;
}

