export const html06DialogModal = (): string => {
	return `<dialog id="dialog-modal" aria-labelledby="dialog-title" aria-describedby="dialog-description">
  <h2 id="dialog-title">Modal Title</h2>
  <p id="dialog-description">This is a description of the modal dialog.</p>
  <button aria-label="Close dialog">Close</button>
</dialog>
<script>
  const dialog = document.getElementById('dialog-modal');
  const closeBtn = dialog.querySelector('[aria-label="Close dialog"]');
  const focusable = Array.from(dialog.querySelectorAll('button, [href], input, select, textarea, [tabindex]:not([tabindex="-1"])'));
  const first = focusable[0];
  const last = focusable[focusable.length - 1];

  dialog.addEventListener('keydown', (event) => {
    if (event.key === 'Tab') {
      event.preventDefault();
      if (event.shiftKey) {
        if (document.activeElement === first) last?.focus();
        else first?.focus();
      } else {
        if (document.activeElement === last) first?.focus();
        else last?.focus();
      }
    }
    if (event.key === 'Escape') {
      dialog.close();
    }
  });

  dialog.addEventListener('click', (event) => {
    if (event.target === dialog) {
      dialog.close();
    }
  });

  closeBtn.addEventListener('click', () => dialog.close());

  dialog.showModal();
</script>`;
};

