import * as fs from 'fs';
import * as path from 'path';

function findTsFiles(dir: string): string[] {
  let results: string[] = [];
  const list = fs.readdirSync(dir);
  for (const file of list) {
    const filePath = path.join(dir, file);
    const stat = fs.statSync(filePath);
    if (stat.isDirectory()) {
      results = results.concat(findTsFiles(filePath));
    } else if (file.endsWith('.ts')) {
      results.push(filePath);
    }
  }
  return results;
}

function parseImports(filePath: string): string[] {
  const content = fs.readFileSync(filePath, 'utf-8');
  const imports: string[] = [];
  const importRegex = /import\s+(?:.*?\s+from\s+)?['"]([^'"]+)['"]/g;
  let match;
  while ((match = importRegex.exec(content)) !== null) {
    const imp = match[1];
    if (imp.startsWith('.') || imp.startsWith('/')) {
      imports.push(imp);
    }
  }
  return imports;
}

function resolveImport(importPath: string, fromDir: string): string | null {
  let resolved = path.resolve(fromDir, importPath);
  const extensions = ['.ts', '.tsx', '.js', '.jsx', ''];
  for (const ext of extensions) {
    const candidate = resolved + ext;
    if (fs.existsSync(candidate)) {
      return candidate;
    }
  }
  for (const ext of extensions) {
    const candidate = path.join(resolved, 'index' + ext);
    if (fs.existsSync(candidate)) {
      return candidate;
    }
  }
  return null;
}

export function detectCycles(rootDir: string): string[][] {
  const files = findTsFiles(rootDir);
  const fileSet = new Set(files);
  const graph = new Map<string, string[]>();

  for (const file of files) {
    const imports = parseImports(file);
    const fromDir = path.dirname(file);
    const neighbors: string[] = [];
    for (const imp of imports) {
      const resolved = resolveImport(imp, fromDir);
      if (resolved && fileSet.has(resolved)) {
        neighbors.push(resolved);
      }
    }
    graph.set(file, neighbors);
  }

  const cycles: string[][] = [];
  const visited = new Set<string>();
  const recStack = new Set<string>();
  const pathStack: string[] = [];

  function dfs(node: string) {
    visited.add(node);
    recStack.add(node);
    pathStack.push(node);

    const neighbors = graph.get(node) || [];
    for (const neighbor of neighbors) {
      if (!visited.has(neighbor)) {
        dfs(neighbor);
      } else if (recStack.has(neighbor)) {
        const cycleStart = pathStack.indexOf(neighbor);
        const cycle = pathStack.slice(cycleStart);
        cycles.push(cycle);
      }
    }

    pathStack.pop();
    recStack.delete(node);
  }

  for (const file of files) {
    if (!visited.has(file)) {
      dfs(file);
    }
  }

  const uniqueCycles: string[][] = [];
  const seen = new Set<string>();
  for (const cycle of cycles) {
    let minIdx = 0;
    for (let i = 1; i < cycle.length; i++) {
      if (cycle[i] < cycle[minIdx]) {
        minIdx = i;
      }
    }
    const normalized = [...cycle.slice(minIdx), ...cycle.slice(0, minIdx)].join(' -> ');
    if (!seen.has(normalized)) {
      seen.add(normalized);
      uniqueCycles.push(cycle);
    }
  }

  return uniqueCycles;
}

export function runCli(args: readonly string[]): number {
  const rootDir = args[0] || '.';
  const cycles = detectCycles(rootDir);
  for (const cycle of cycles) {
    console.log(cycle.join(' -> '));
  }
  return cycles.length > 0 ? 1 : 0;
}

