export function fftBigintMultiplyDigitArrays(a: number[], b: number[]): number[] {
    if (a.length === 0 || b.length === 0) return [];
    if (a.every(v => v === 0) || b.every(v => v === 0)) return [0];

    const aRev = a.slice().reverse();
    const bRev = b.slice().reverse();

    let n = 1;
    while (n < aRev.length + bRev.length) n <<= 1;

    const fa = new Array(2 * n).fill(0);
    const fb = new Array(2 * n).fill(0);

    for (let i = 0; i < aRev.length; i++) fa[i << 1] = aRev[i];
    for (let i = 0; i < bRev.length; i++) fb[i << 1] = bRev[i];

    function fft(arr: number[], invert: boolean) {
        const len = arr.length >> 1;
        let j = 0;
        for (let i = 1; i < len; i++) {
            const bit = len >> 1;
            for (; j & bit; bit >>= 1) j ^= bit;
            j ^= bit;
            if (i < j) {
                const tr = arr[i << 1]; const ti = arr[(i << 1) + 1];
                arr[i << 1] = arr[j << 1]; arr[(i << 1) + 1] = arr[(j << 1) + 1];
                arr[j << 1] = tr; arr[(j << 1) + 1] = ti;
            }
        }
        for (let l = 2; l <= len; l <<= 1) {
            const ang = (2 * Math.PI / l) * (invert ? -1 : 1);
            const wlen_r = Math.cos(ang);
            const wlen_i = Math.sin(ang);
            for (let i = 0; i < len; i += l) {
                let w_r = 1;
                let w_i = 0;
                for (let k = 0; k < l >> 1; k++) {
                    const i1 = (i + k) << 1;
                    const i2 = (i + k + (l >> 1)) << 1;
                    const u_r = arr[i1];
                    const u_i = arr[i1 + 1];
                    const v_r = arr[i2] * w_r - arr[i2 + 1] * w_i;
                    const v_i = arr[i2] * w_i + arr[i2 + 1] * w_r;
                    arr[i1] = u_r + v_r;
                    arr[i1 + 1] = u_i + v_i;
                    arr[i2] = u_r - v_r;
                    arr[i2 + 1] = u_i - v_i;
                    const next_w_r = w_r * wlen_r - w_i * wlen_i;
                    const next_w_i = w_r * wlen_i + w_i * wlen_r;
                    w_r = next_w_r;
                    w_i = next_w_i;
                }
            }
        }
        if (invert) {
            for (let i = 0; i < len; i++) {
                arr[i << 1] /= len;
                arr[(i << 1) + 1] /= len;
            }
        }
    }

    fft(fa, false);
    fft(fb, false);

    for (let i = 0; i < 2 * n; i += 2) {
        const r1 = fa[i], i1 = fa[i + 1];
        const r2 = fb[i], i2 = fb[i + 1];
        fa[i] = r1 * r2 - i1 * i2;
        fa[i + 1] = r1 * i2 + i1 * r2;
    }

    fft(fa, true);

    const res = new Array(a.length + b.length - 1).fill(0);
    for (let i = 0; i < res.length; i++) {
        res[i] = Math.round(fa[i << 1]);
    }

    for (let i = 0; i < res.length - 1; i++) {
        const carry = Math.floor(res[i] / 10);
        res[i] %= 10;
        res[i + 1] += carry;
    }
    while (res[res.length - 1] >= 10) {
        const carry = Math.floor(res[res.length - 1] / 10);
        res[res.length - 1] %= 10;
        res.push(carry);
    }

    while (res.length > 1 && res[res.length - 1] === 0) {
        res.pop();
    }

    return res.reverse();
}

