export function lruCache(capacity: number, operations: readonly (readonly ['get' | 'put', number, number?])[]): (number | null)[] {
  const cache = new Map<number, number>();
  const result: (number | null)[] = [];

  for (const op of operations) {
    if (op[0] === 'get') {
      const key = op[1];
      if (cache.has(key)) {
        const val = cache.get(key)!;
        cache.delete(key);
        cache.set(key, val);
        result.push(val);
      } else {
        result.push(null);
      }
    } else {
      const key = op[1];
      const val = op[2]!;
      if (cache.has(key)) {
        cache.delete(key);
      } else if (cache.size === capacity && capacity > 0) {
        cache.delete(cache.keys().next().value);
      }
      if (capacity > 0) {
        cache.set(key, val);
      }
    }
  }
  return result;
}

