export function minStack(operations: readonly (readonly ['push' | 'pop' | 'top' | 'getMin', number?])[]): (number | null)[] {
    const stack: { val: number; min: number }[] = [];
    const results: (number | null)[] = [];

    for (const op of operations) {
        switch (op[0]) {
            case 'push':
                const val = op[1] as number;
                const newMin = stack.length === 0 ? val : Math.min(val, stack[stack.length - 1].min);
                stack.push({ val, min: newMin });
                break;
            case 'pop':
                stack.pop();
                break;
            case 'top':
                results.push(stack.length > 0 ? stack[stack.length - 1].val : null);
                break;
            case 'getMin':
                results.push(stack.length > 0 ? stack[stack.length - 1].min : null);
                break;
        }
    }

    return results;
}

