export function dijkstraShortestPath(nodeCount: number, edges: readonly (readonly [number, number, number])[], start: number, end: number): number | null {
    const adj: number[][][] = Array.from({ length: nodeCount }, () => []);
    for (const [u, v, w] of edges) {
        adj[u].push([v, w]);
    }

    const dist: number[] = new Array(nodeCount).fill(Infinity);
    dist[start] = 0;
    const heap: [number, number][] = [[0, start]];

    while (heap.length > 0) {
        const top = heap[0];
        const last = heap.pop()!;
        if (heap.length > 0) {
            heap[0] = last;
            let i = 0;
            while (true) {
                let s = i;
                const l = 2 * i + 1;
                const r = 2 * i + 2;
                if (l < heap.length && heap[l][0] < heap[s][0]) s = l;
                if (r < heap.length && heap[r][0] < heap[s][0]) s = r;
                if (s === i) break;
                const temp = heap[s]; heap[s] = heap[i]; heap[i] = temp;
                i = s;
            }
        }

        const [d, u] = top;
        if (d > dist[u]) continue;
        if (u === end) return d;

        for (const [v, w] of adj[u]) {
            const nd = d + w;
            if (nd < dist[v]) {
                dist[v] = nd;
                heap.push([nd, v]);
                let i = heap.length - 1;
                while (i > 0) {
                    const p = (i - 1) >> 1;
                    if (heap[p][0] <= heap[i][0]) break;
                    const temp = heap[p]; heap[p] = heap[i]; heap[i] = temp;
                    i = p;
                }
            }
        }
    }

    return dist[end] === Infinity ? null : dist[end];
